#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    vector<int> F(N + 1); // 1-indexed
    for (int i = 1; i <= N; ++i) {
        cin >> F[i];
    }

    vector<int> state(N + 1, 0); // 0=unvisited, 1=visiting, 2=processed
    vector<bool> loopy(N + 1, false);

    for (int i = 1; i <= N; ++i) {
        if (state[i] != 0) continue;
        int cur = i;
        // traverse until we hit a visited node or a dead end (0)
        while (cur != 0 && state[cur] == 0) {
            state[cur] = 1; // visiting
            cur = F[cur];
        }
        // Now cur is either 0, a node marked visiting (cycle found), or a node marked processed
        if (cur != 0 && state[cur] == 1) {
            // we found a cycle: mark all nodes in the cycle as loopy
            int cycle_start = cur;
            int node = cycle_start;
            do {
                loopy[node] = true;
                node = F[node];
            } while (node != cycle_start);
        }
        // Mark all nodes in this traversal path as processed (except those in cycle already done)
        // Walk again from the start and mark processed
        cur = i;
        while (cur != 0 && state[cur] != 2) {
            state[cur] = 2; // processed
            cur = F[cur];
        }
    }

    int count_not_loopy = 0;
    for (int i = 1; i <= N; ++i) {
        if (!loopy[i]) ++count_not_loopy;
    }

    cout << count_not_loopy << "\n";

    return 0;
}
